#define aarch64_cas_acq_rel(ptr, expected, desired)      \
    _Generic((ptr),                                      \
        char*:         __aarch64_cas1_acq_rel,  \
        short*:        __aarch64_cas2_acq_rel,  \
        int*:          __aarch64_cas4_acq_rel,  \
        long long*:    __aarch64_cas8_acq_rel   \
    )(ptr, expected, desired)

